import type {
  Answer,
  BreadcrumbList,
  FAQPage,
  ListItem,
  Organization,
  Question,
  WebSite,
} from "@vendor/seo/json-ld";

export interface Crumb {
  name: string;
  url: string;
}

export function buildOrganizationEntity(): Organization {
  return {
    "@type": "Organization",
    "@id": "https://lightfast.ai/#organization",
    name: "Lightfast",
    url: "https://lightfast.ai",
    logo: {
      "@type": "ImageObject",
      url: "https://lightfast.ai/og.png",
    },
    sameAs: [
      "https://x.com/lightfastai",
      "https://github.com/lightfastai",
      "https://www.linkedin.com/company/lightfastai",
    ],
  };
}

export function buildWebSiteEntity(): WebSite {
  return {
    "@type": "WebSite",
    "@id": "https://lightfast.ai/#website",
    name: "Lightfast",
    url: "https://lightfast.ai",
    publisher: { "@id": "https://lightfast.ai/#organization" },
  };
}

export function buildBreadcrumbList(crumbs: Crumb[]): BreadcrumbList {
  return {
    "@type": "BreadcrumbList",
    "@id": `${crumbs.at(-1)?.url ?? ""}#breadcrumb`,
    itemListElement: crumbs.map(
      (crumb, index) =>
        ({
          "@type": "ListItem",
          position: index + 1,
          name: crumb.name,
          item: crumb.url,
        }) satisfies ListItem
    ),
  };
}

export function buildFaqEntity(
  items: Array<{ question: string; answer: string }>,
  pageId: string
): FAQPage {
  return {
    "@type": "FAQPage",
    "@id": `${pageId}#faq`,
    mainEntity: items.map(
      (item) =>
        ({
          "@type": "Question" as const,
          name: item.question,
          acceptedAnswer: {
            "@type": "Answer" as const,
            text: item.answer,
          } satisfies Answer,
        }) satisfies Question
    ),
  };
}

import type { Thing, WithContext } from "schema-dts";

// Type for JSON-LD Graph structure.
// @context is intentionally `string` (not the literal "https://schema.org") to
// stay spec-compliant — JSON-LD allows any URI, inline objects, or arrays.
// Use WithContext<Thing> when a strict "https://schema.org" literal is needed.
interface GraphContext {
  "@context":
    | string
    | Record<string, unknown>
    | (string | Record<string, unknown>)[];
  "@graph": Thing[];
}

// Union type supporting both single entities and graph structures
type JsonLdData = WithContext<Thing> | GraphContext;

interface JsonLdProps {
  code: JsonLdData;
}

const escapeJsonForHtml = (json: string): string =>
  json
    .replace(/</g, "\\u003c")
    .replace(/>/g, "\\u003e")
    .replace(/&/g, "\\u0026")
    .replace(/\u2028/g, "\\u2028")
    .replace(/\u2029/g, "\\u2029");

export const JsonLd = ({ code }: JsonLdProps) => (
  <script
    // biome-ignore lint/security/noDangerouslySetInnerHtml: JSON-LD must be injected via script tag; content is escaped
    dangerouslySetInnerHTML={{
      __html: escapeJsonForHtml(JSON.stringify(code)),
    }}
    type="application/ld+json"
  />
);

// Export types for use in components
export type { GraphContext, JsonLdData };

// Re-export commonly used schema types for convenience
export type {
  Answer,
  // Content types
  Article,
  Blog,
  BlogPosting,
  BreadcrumbList,
  // Event types
  Event,
  FAQPage,
  HowTo,
  HowToStep,
  // Media types
  ImageObject,
  ListItem,
  Offer,
  // Organization types
  Organization,
  // Person types
  Person,
  Product,
  Question,
  Service,
  // Product/Service types
  SoftwareApplication,
  TechArticle,
  // Core types
  Thing,
  VideoObject,
  WebPage,
  // Website types
  WebSite,
  WithContext,
} from "schema-dts";

